const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [
    {
      role: "user",
      content: "What's the stock price for AAPL?"
    }
  ],
  tools: [
    {
      name: "get_stock_price",
      description: "Get the current stock price for a given symbol...",
      input_schema: {
        type: "object",
        properties: { symbol: { type: "string" } },
        required: ["symbol"]
      }
    }
  ],
  tool_choice: { type: "auto" } // Default: Claude decides
});

{
  "role": "assistant",
  "content": [
    {
      "type": "text",
      "text": "I need to check the stock price for AAPL."
    },
    {
      "type": "tool_use",
      "id": "toolu_01A12v3xX",
      "name": "get_stock_price",
      "input": { "symbol": "AAPL" }
    }
  ],
  "stop_reason": "tool_use" // ← Control flow signal
}

const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [{ role: "user", content: "What's AAPL's stock price?" }],
  tools: [getStockPriceTool],
  tool_choice: { type: "auto" } // Claude decides when to use tools
});

// Light instruction: measurably increases tool use
const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  system: "Use the tools to investigate before responding.",
  messages: [{ role: "user", content: "What's the weather in Boston?" }],
  tools: [getWeatherTool]
});

// Stronger form: forces tool-first behavior
const response2 = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  system: "Always call a tool first before responding.",
  messages: [{ role: "user", content: "What's the weather in Boston?" }],
  tools: [getWeatherTool]
});

// Conservative: keeps triggering behavior minimal
const response3 = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  system: "Use your judgment about whether to call a tool or respond directly.",
  messages: [{ role: "user", content: "What's the weather in Boston?" }],
  tools: [getWeatherTool]
});

const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [{ role: "user", content: "What's AAPL's stock price?" }],
  tools: [getStockPriceTool],
  tool_choice: { type: "any" } // Claude MUST call at least one tool
});

const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [{ role: "user", content: "AAPL price?" }],
  tools: [
    {
      name: "get_stock_price",
      description: "Get current stock price...",
      input_schema: { ... },
      strict: true // Ensure Claude's tool calls match schema exactly
    }
  ]
});

// User requests multiple items
const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [{ role: "user", content: "What are stock prices for AAPL and GOOGL?" }],
  tools: [getStockPriceTool]
});

// Claude returns multiple tool_use blocks
const toolUseBlocks = response.content.filter(c => c.type === "tool_use");
console.log(toolUseBlocks.length); // 2

// Execute in parallel
const results = await Promise.all(
  toolUseBlocks.map(block => executeTool(block.name, block.input))
);
